                        case LOGIN_USERNAME:
                        case LOGIN_WEBAUTHN:
                        case X509_CONFIRM:
                            b = UriBuilder.fromUri(Urls.realmLoginPage(baseUri, realm.getName()));
                            break;
                        case REGISTER:
